require __DIR__.'/../includes/bootstrap.php';$slug=trim($_GET['slug']??'');$c=companies_schema_ready()?company_by_slug($slug):null;if(!$c){http_response_code(404);exit('Company not found.');}$u=user();if($c['status']!=='approved'&&(!$u||!can_manage_company($c,$u))){http_response_code(404);exit('Company not found.');}$members=db()->prepare("SELECT u.display_name,u.username,cm.position_title,cm.relationship_type,cm.company_role FROM company_members cm JOIN users u ON u.id=cm.user_id WHERE cm.company_id=? AND cm.status='active' AND cm.company_role<>'fan' ORDER BY FIELD(cm.company_role,'owner','company_admin','member'),u.display_name");$members->execute([(int)$c['id']]);$members=$members->fetchAll();app_header($c['name']);$banner=$c['banner_path']?"background-image:linear-gradient(rgba(5,5,11,.18),rgba(5,5,11,.82)),url('".e(base_url($c['banner_path']))."')":'';
?><section class="company-profile-hero" style="<?=$banner?>"><?php if($c['logo_path']):?><img class="company-profile-logo" src="<?=e(base_url($c['logo_path']))?>" alt="<?=e($c['name'])?> logo"><?php endif?><div><p class="eyebrow">APPROVED COMPANY</p><h1><?=e($c['name'])?></h1><p><?=e($c['short_description'])?></p></div></section><section class="profile-grid"><article class="app-card profile-main"><h2>About</h2><p><?=nl2br(e($c['description']?:'No company description has been added yet.'))?></p><?php if($c['website']):?><p><a class="button primary" href="<?=e($c['website'])?>" rel="noopener" target="_blank">Visit Website</a></p><?php endif?></article><aside class="profile-side"><article class="app-card"><h2>Details</h2><dl><?php if($c['category']):?><dt>Category</dt><dd><?=e($c['category'])?></dd><?php endif?><?php if($c['location']):?><dt>Location</dt><dd><?=e($c['location'])?></dd><?php endif?><?php if($c['founded_year']):?><dt>Founded</dt><dd><?=(int)$c['founded_year']?></dd><?php endif?><?php if($c['public_email']):?><dt>Email</dt><dd><a href="mailto:<?=e($c['public_email'])?>"><?=e($c['public_email'])?></a></dd><?php endif?></dl></article><?php if($members):?><article class="app-card"><h2>Team</h2><?php foreach($members as $m):?><p><a href="<?=e(base_url('profile.php?u='.urlencode($m['username'])))?>"><strong><?=e($m['display_name'])?></strong></a><br><span class="muted"><?=e($m['position_title']?:ucwords(str_replace('_',' ',$m['relationship_type'])))?></span></p><?php endforeach?></article><?php endif?></aside></section><?php app_footer();
